INSERT OR REPLACE INTO products (id, name_jp, name_cn, name_en, vol, code, price_jpy, is_sealed, is_hot, image_url, description_jp, description_cn, stock_count) VALUES
('gem-pack-vol1', 'ジェムパック Vol.1', 'ジェムパック 第1弾', 'Gem Pack VOL.1', 'VOL.1', 'SV3a', 7500, 1, 1, '/images/vol1-wiki-poster.webp', 'パルデア地方の御三家ニャオハ・ホゲータ・クワッスが登場。全カードがキラカード仕様。キャプテンピカチュウ収録。2025年1月17日発売。', '帕底亚御三家新叶喵、呆火鳄、润水鸭登场。全卡闪卡。收录船长皮卡丘。', 10),
('gem-pack-vol2', 'ジェムパック Vol.2', 'ジェムパック 第2弾', 'Gem Pack VOL.2', 'VOL.2', 'SV3b', 9580, 1, 1, '/images/gem-pack-vol2.png', 'イーブイと全進化形態が集結。ニンフィア表紙。4枚つなぎイラストカード収録。ポケモンV・VMAXカード搭载。2025年5月16日発売。', '伊布全进化形态集结。仙子伊布封面。收录4张拼接插画卡。含V/VMAX卡。', 10),
('gem-pack-vol3', 'ジェムパック Vol.3', 'ジェムパック 第3弾', 'Gem Pack VOL.3', 'VOL.3', 'SV3c', 7400, 1, 0, '/images/vol3-wiki-poster.png', '夜行性ポケモンをテーマにゲンガーが表紙。ポケモンexキラカード、9種のアートイラストキラカード収録。マスターボール柄カードも。2025年9月26日発売。', '夜行寶可夢テーマ、耿鬼表紙。exホロ、万が国 예술 ilustores カード収録。大師球パターソカード含む。', 10),
('gem-pack-vol4', 'ジェムパック Vol.4', 'ジェムパック 第4弾', 'Gem Pack VOL.4', 'VOL.4', 'SV3d', 6730, 0, 0, '/images/vol4-wiki-poster.png', 'ポニータ＆ギャロップが表纸の最新弾。新春テーマ。属性シンボル・マスターボール柄・金箔押しカード収録。アートイラストカードも充実。2026年2月6日発売。', '小火马与烈焰马封面的最新弹。新春主题。收录属性符号、大师球花纹、烫金卡。', 10),
('gem-pack-vol5', 'ジェムパック Vol.5', 'ジェムパック 第5弹', 'Gem Pack VOL.5', 'VOL.5', 'SV3e', 0, 1, 0, '/images/vol5-cover.png', '地平線の冒険をテーマにした最新弾。蒂蕾喵・炙烫鳄・涌跃鸭が登場。キャプテンピカチュウとフリードの冒険を描いたアートカード収録。2026年4月24日発売予定。', '以地平线冒险为主题的最新弹。蒂蕾喵、炙烫鳄、涌跃鸭登场。收录船长皮卡丘与弗里德冒险主题艺术卡。2026年4月24日发售。', 10);
